"use client";

import { forwardRef } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "btn inline-flex items-center justify-center gap-2 whitespace-nowrap font-medium transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-amber-400 disabled:opacity-40 disabled:pointer-events-none select-none",
  {
    variants: {
      variant: {
        primary:   "bg-amber-500 text-black hover:bg-amber-400 active:scale-[0.98] shadow-[0_4px_20px_rgba(245,158,11,0.2)]",
        secondary: "bg-[var(--color-elevated)] text-[var(--color-text-primary)] border border-[var(--color-border)] hover:border-[var(--color-text-muted)] hover:bg-[var(--color-border)]",
        ghost:     "bg-transparent text-[var(--color-text-secondary)] hover:bg-[var(--color-elevated)] hover:text-[var(--color-text-primary)]",
        danger:    "bg-red-500/10 text-red-400 border border-red-500/20 hover:bg-red-500/20",
        outline:   "bg-transparent border border-amber-500/40 text-amber-400 hover:bg-amber-500/10",
      },
      size: {
        xs:  "h-7 px-3 text-xs rounded-md",
        sm:  "h-8 px-4 text-sm rounded-md",
        md:  "h-10 px-5 text-sm rounded-[var(--radius-md)]",
        lg:  "h-12 px-7 text-base rounded-[var(--radius-lg)]",
        xl:  "h-14 px-8 text-lg rounded-[var(--radius-lg)]",
        icon:"h-9 w-9 rounded-[var(--radius-md)]",
      },
    },
    defaultVariants: { variant: "primary", size: "md" },
  }
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  loading?: boolean;
}

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, loading, children, disabled, ...props }, ref) => (
    <button
      ref={ref}
      className={cn(buttonVariants({ variant, size }), className)}
      disabled={disabled || loading}
      {...props}
    >
      {loading && (
        <svg className="animate-spin h-4 w-4" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
        </svg>
      )}
      {children}
    </button>
  )
);
Button.displayName = "Button";
