"use client";

import Link from "next/link";
import { useRouter } from "next/navigation";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { motion } from "framer-motion";
import { Mail, Lock, ArrowRight } from "lucide-react";
import { toast } from "sonner";
import { loginSchema, type LoginInput } from "@/features/auth/schemas";
import { authService } from "@/services/auth.service";
import { useAuthStore } from "@/store/auth.store";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import type { Metadata } from "next";

export default function LoginPage() {
  const router = useRouter();
  const setAuth = useAuthStore((s) => s.setAuth);

  const { register, handleSubmit, formState: { errors, isSubmitting } } = useForm<LoginInput>({
    resolver: zodResolver(loginSchema),
  });

  const onSubmit = async (data: LoginInput) => {
    try {
      const { user, token } = await authService.login(data.email, data.password);
      setAuth(user, token);
      toast.success(`Welcome back, ${user.full_name.split(" ")[0]}!`);
      router.push("/main");
    } catch {
      toast.error("Invalid email or password");
    }
  };

  return (
    <div className="min-h-dvh bg-[var(--color-void)] flex">
      {/* Left panel — branding */}
      <div className="hidden lg:flex flex-col flex-1 relative overflow-hidden bg-[var(--color-surface)] border-r border-[var(--color-border)]">
        <div className="absolute inset-0 grid-overlay" />
        <div className="relative z-10 flex flex-col h-full p-12">
          <Link href="/" className="flex items-center gap-3">
            <div className="w-10 h-10 bg-amber-500 rounded-[8px] flex items-center justify-center">
              <span className="font-display text-black text-base tracking-wider">CB</span>
            </div>
            <span className="font-display text-2xl tracking-widest">CARSANDBIKES</span>
          </Link>
          <div className="flex-1 flex flex-col justify-center">
            <motion.div
              initial={{ opacity: 0, x: -30 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.6 }}
            >
              <h1 className="font-display text-7xl leading-none text-[var(--color-text-primary)] mb-6">
                DRIVE<br />
                <span className="text-amber-400">YOUR</span><br />
                DEAL.
              </h1>
              <p className="text-[var(--color-text-secondary)] text-lg max-w-xs leading-relaxed">
                Premium vehicles. Verified sellers. Real-time negotiation.
              </p>
            </motion.div>
          </div>
          <p className="text-[var(--color-text-muted)] text-sm">
            © 2025 CarsAndBikes. All rights reserved.
          </p>
        </div>
      </div>

      {/* Right panel — form */}
      <div className="flex-1 flex items-center justify-center p-6 lg:p-12">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.4 }}
          className="w-full max-w-sm"
        >
          {/* Mobile logo */}
          <div className="lg:hidden flex items-center gap-2 mb-8">
            <div className="w-8 h-8 bg-amber-500 rounded-[6px] flex items-center justify-center">
              <span className="font-display text-black text-sm">CB</span>
            </div>
            <span className="font-display text-xl tracking-widest">CARSANDBIKES</span>
          </div>

          <h2 className="font-display text-4xl tracking-wide mb-1">WELCOME BACK</h2>
          <p className="text-[var(--color-text-secondary)] text-sm mb-8">
            Sign in to continue
          </p>

          <form onSubmit={handleSubmit(onSubmit)} className="space-y-4" noValidate>
            <Input
              label="Email"
              type="email"
              placeholder="you@example.com"
              autoComplete="email"
              icon={<Mail className="h-4 w-4" />}
              error={errors.email?.message}
              {...register("email")}
            />
            <Input
              label="Password"
              type="password"
              placeholder="••••••••"
              autoComplete="current-password"
              icon={<Lock className="h-4 w-4" />}
              error={errors.password?.message}
              {...register("password")}
            />

            <Button
              type="submit"
              size="lg"
              loading={isSubmitting}
              className="w-full mt-2"
            >
              Sign In <ArrowRight className="h-4 w-4" />
            </Button>
          </form>

          <div className="mt-6 text-center text-sm text-[var(--color-text-muted)]">
            Don&apos;t have an account?{" "}
            <Link href="/auth/register" className="text-amber-400 hover:text-amber-300 transition-colors font-medium">
              Join free
            </Link>
          </div>
        </motion.div>
      </div>
    </div>
  );
}
